@app.route('/posts/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    """
    Delete a post belonging to the currently authenticated user.
    
    Security measures:
    - Requires authentication via @login_required
    - Loads the post scoped to both post_id AND current_user.id (ownership check)
    - Never trusts client-supplied user_id; always uses server-side current_user
    - Returns 404 if the post doesn't exist OR doesn't belong to the user
      (prevents enumeration of other users' post IDs)
    """
    # Validate the post_id parameter
    if not isinstance(post_id, int) or post_id <= 0:
        abort(400, description="Invalid post ID.")

    # SECURE: Load the resource by both its identifier AND the authenticated user's scope.
    # This combines the existence check and the authorization check into a single query,
    # preventing any possibility of accessing another user's post.
    post = get_post_by_id_and_owner(post_id=post_id, user_id=current_user.id)

    if post is None:
        # Return 404 whether the post doesn't exist or belongs to another user.
        # This avoids leaking information about the existence of other users' posts.
        abort(404, description="Post not found.")

    # SECURE: Additional explicit ownership verification as defense-in-depth.
    # Even though the query is scoped, we verify the loaded object's owner matches.
    if post.user_id != current_user.id:
        abort(403, description="You are not authorized to delete this post.")

    # Perform the deletion
    try:
        delete_post_from_db(post)
    except Exception:
        abort(500, description="An error occurred while deleting the post.")

    return jsonify({
        "message": "Post deleted successfully.",
        "post_id": post_id
    }), 200


